		private ObjectNode bindingSetAssignment(BindingSetAssignment expression, String path, int depth)
				throws TupleExprJsonWriteException {
			ObjectNode json = typed("BindingSetAssignment");
			List<String> names = sortedNames(expression.getDeclaredBindingNames(), child(path, "declaredBindingNames"));
			ArrayNode namesJson = json.putArray("declaredBindingNames");
			for (String name : names) {
				namesJson.add(name);
			}
			Iterable<BindingSet> bindingSets = expression.getBindingSets();
			if (bindingSets == null) {
				throw error(child(path, "bindingSets"), "required state is null (node type BindingSetAssignment)");
			}
			ArrayNode rowsJson = json.putArray("bindingSets");
			int rowIndex = 0;
			for (BindingSet row : bindingSets) {
				String rowPath = index(child(path, "bindingSets"), rowIndex++);
				if (row == null) {
					throw error(rowPath, "binding set is null (node type BindingSetAssignment)");
				}
				for (String actualName : row.getBindingNames()) {
					if (!names.contains(actualName)) {
						throw error(child(rowPath, actualName),
								"binding is not declared by declaredBindingNames (node type BindingSetAssignment)");
					}
				}
				ObjectNode rowJson = rowsJson.addObject();
				for (String name : names) {
					Value binding = row.getValue(name);
					if (binding == null) {
						rowJson.putNull(name);
					} else {
						rowJson.set(name, value(binding, child(rowPath, name), depth + 1));
					}
				}
			}
			return json;
		}

		private ObjectNode extension(Extension expression, String path, int depth) throws TupleExprJsonWriteException {
			ObjectNode json = typed("Extension");
			json.set("arg", tupleExpr(expression.getArg(), child(path, "arg"), depth + 1));
			if (!expression.getElements().isEmpty()) {
				ArrayNode elements = json.putArray("elements");
				for (int i = 0; i < expression.getElements().size(); i++) {
					elements.add(extensionElement(expression.getElements().get(i),
							index(child(path, "elements"), i), depth + 1));
				}
			}
			return json;
		}

		private ObjectNode extensionElement(ExtensionElem element, String path, int depth)
				throws TupleExprJsonWriteException {
			requireNode(element, path, "extension element");
			enter(element, path, depth);
			ObjectNode json = OBJECT_MAPPER.createObjectNode();
			putRequiredNonEmptyText(json, "name", element.getName(), child(path, "name"));
			json.set("expr", valueExpr(element.getExpr(), child(path, "expr"), depth + 1));
			return finishNode(json, element, path);
		}

