		private ObjectNode service(Service expression, String path, int depth) throws TupleExprJsonWriteException {
			ObjectNode json = typed("Service");
			json.set("serviceRef", variable(expression.getServiceRef(), child(path, "serviceRef"), depth + 1));
			json.set("arg", tupleExpr(expression.getServiceExpr(), child(path, "arg"), depth + 1));
			putRequiredText(json, "serviceExpressionString", expression.getServiceExpressionString(),
					child(path, "serviceExpressionString"));
			if (expression.getPrefixDeclarations() != null) {
				ObjectNode prefixes = json.putObject("prefixDeclarations");
				List<String> names = sortedNames(expression.getPrefixDeclarations().keySet(),
						child(path, "prefixDeclarations"));
				for (String name : names) {
					String namespace = expression.getPrefixDeclarations().get(name);
					putRequiredText(prefixes, name, namespace, child(child(path, "prefixDeclarations"), name));
				}
			}
			putOptionalText(json, "baseURI", expression.getBaseURI(), child(path, "baseURI"));
			if (expression.isSilent()) {
				json.put("silent", true);
			}
			return json;
		}

